#include <iostream>
using namespace std;

bool isSorted(int arr[], int n) {
  for(int I = 1; I < n; i++) {
    if(arr[i] < arr[i - 1]) {
      return false;
    }
  }
  return true;
}

int main() {
  int arr[] = {1, 2, 3, 4, 5};
  int n = sizeof(arr)/sizeof(arr[0]);
  if(isSorted(arr, n)) {
    cout << "Array is sorted." << endl;
  } else {
    cout << "Array is not sorted." << endl;
  }
  return 0;
}
```

